rubric.en:
Expected code/algorithm:
sufpref(a) {
  m = a.size();
  ipref = -1;
  for (i = 0; i < m-1; ++i) {
    j = 0;
    while (j <= i && a[i-j] == a[m-1-j]) {
      ++j;
    }
    if (j > i) ipref = i;
  }
  return ipref;
}

